from __future__ import annotations

# AUTO-GENERATED MATCHER SHIM (REQ-003-007)
# Matcher: Bash(git commit*|git ci*)
# Generated by build/scripts/generate_hooks.py (REQ-003-007).
# DO NOT EDIT BY HAND - regenerated on every build. Apply NO-REGEN
# sentinel ("# NO-REGEN" or sidecar .noregen) to opt out.
import os as _os
import sys as _sys
import io as _io
import json as _json
import re as _re
import fnmatch as _fnmatch

_MATCHER = 'Bash(git commit*|git ci*)'

# Cap stdin read so a malicious or buggy upstream cannot OOM the shim
# (CWE-400). Mirrors push_guard_base.MAX_STDIN_BYTES (1 MiB) with a
# small headroom; real Claude/Copilot tool_input commands are well
# below this limit. The cap belongs at the SHIM layer because the
# shim reads stdin BEFORE delegating to the wrapped script. Without
# it, the wrapped script's own cap is applied too late: the OOM has
# already happened.
_SHIM_MAX_STDIN_BYTES = 2 * 1024 * 1024


def _shim_classify(pattern):
    # MIRROR: classify_matcher (build-time, build/scripts/generate_hooks.py)
    # and _shim_classify (runtime, this inlined copy) MUST agree on the
    # grammar. Update both when the grammar changes.
    if pattern.startswith("^") and pattern.endswith("$"):
        return "regex", {"pattern": pattern}
    m = _re.match(r"^([A-Za-z_][A-Za-z0-9_]*)\((.*)\)$", pattern)
    if m:
        return "tool-glob", {"toolName": m.group(1), "argsGlob": m.group(2)}
    return "bare", {"toolName": pattern}


def _shim_normalize_args(tool_args):
    r"""Stringify and whitespace-normalize tool_input for fnmatch comparison.

    REQ-003-007: collapse \s+ to a single space and strip ends. Pattern
    is NOT normalized; authors write patterns assuming single spaces.
    """
    if isinstance(tool_args, dict):
        # Bash hooks place command under "command"; keep this fallback
        # path narrow but correct for the live corpus.
        cmd = tool_args.get("command")
        if isinstance(cmd, str):
            text = cmd
        else:
            text = _json.dumps(tool_args, sort_keys=True)
    elif isinstance(tool_args, str):
        text = tool_args
    elif tool_args is None:
        text = ""
    else:
        text = str(tool_args)
    return _re.sub(r"\s+", " ", text).strip()


def _shim_glob_match(args_glob, tool_args_norm):
    """Match args_glob against tool_args_norm with `|` as alternation.

    fnmatch treats `|` as a literal. Authors expect Claude semantics
    where each `|` branch is a separate glob alternation. Split on
    top-level `|` and OR-fold the results.
    """
    branches = args_glob.split("|") if args_glob else [""]
    for branch in branches:
        if _fnmatch.fnmatchcase(tool_args_norm, branch):
            return True
    return False


def _shim_parse_json_string(raw_value, field_name):
    if isinstance(raw_value, str):
        stripped = raw_value.lstrip()
        if not stripped or stripped[0] not in "{[\"":
            return raw_value
        try:
            return _json.loads(raw_value)
        except ValueError as exc:
            print(
                "matcher-shim [{}]: {} is not valid JSON: {}".format(
                    _MATCHER, field_name, exc
                ),
                file=_sys.stderr,
            )
            return raw_value
    return raw_value


def _shim_tool_input_from_call_args(raw_args):
    return _shim_parse_json_string(raw_args, "toolCalls.args")


def _shim_tool_input_from_tool_args(raw_args):
    return _shim_parse_json_string(raw_args, "toolArgs")


def _shim_candidate_payloads(payload):
    tool_calls = payload.get("toolCalls")
    if isinstance(tool_calls, list):
        candidates = []
        for call in tool_calls:
            if not isinstance(call, dict):
                continue
            name = call.get("name")
            if not isinstance(name, str):
                continue
            candidate = dict(payload)
            candidate.pop("toolCalls", None)
            candidate["tool_name"] = name
            candidate["tool_input"] = _shim_tool_input_from_call_args(call.get("args"))
            if "id" in call:
                candidate["tool_call_id"] = call.get("id")
            candidates.append(candidate)
        return candidates
    return [payload]


def _shim_match_candidate(payload, kind, params):
    # Support both VS Code-compatible snake_case (PascalCase event names)
    # and native camelCase (camelCase event names) payloads.
    # Copilot CLI sends snake_case when the event key is PascalCase,
    # camelCase when the event key is camelCase. See issue #2290.
    tool_name = payload.get("tool_name")
    if tool_name is None:
        tool_name = payload.get("toolName")
    if not isinstance(tool_name, str):
        raise ValueError("hook input missing string `tool_name`/`toolName` field")
    if kind == "regex":
        return _re.fullmatch(params["pattern"], tool_name) is not None
    if kind == "tool-glob":
        if tool_name != params["toolName"]:
            return False
        tool_args = payload.get("tool_input")
        if tool_args is None:
            tool_args = payload.get("toolArgs")
        # camelCase payloads send toolArgs as a JSON string, not a parsed
        # object. Parse it so _shim_normalize_args can extract "command".
        tool_args = _shim_tool_input_from_tool_args(tool_args)
        norm_args = _shim_normalize_args(tool_args)
        return _shim_glob_match(params["argsGlob"], norm_args)
    # bare
    return tool_name == params["toolName"]


def _shim_select_payload(payload):
    kind, params = _shim_classify(_MATCHER)
    candidates = _shim_candidate_payloads(payload)
    if not candidates:
        return None
    for candidate in candidates:
        if _shim_match_candidate(candidate, kind, params):
            return candidate
    return None


def _shim_should_fire(payload):
    return _shim_select_payload(payload) is not None


def _shim_replay_bytes(payload, raw):
    selected = _shim_select_payload(payload)
    if selected is None:
        return raw
    replay = dict(selected)
    changed = replay is not payload
    tool_name = replay.get("tool_name")
    if tool_name is None and isinstance(replay.get("toolName"), str):
        replay["tool_name"] = replay["toolName"]
        changed = True
    tool_input = replay.get("tool_input")
    if tool_input is None and "toolArgs" in replay:
        replay["tool_input"] = _shim_tool_input_from_tool_args(replay.get("toolArgs"))
        changed = True
    if not changed:
        return raw
    if payload.get("tool_name") is not None:
        return raw
    return _json.dumps(replay, separators=(",", ":")).encode("utf-8")


def _shim_dispatch():
    try:
        _raw = _sys.stdin.buffer.read(_SHIM_MAX_STDIN_BYTES + 1)
    except Exception as exc:  # pragma: no cover - defensive
        print(
            "matcher-shim [{}]: failed to buffer stdin: {}".format(_MATCHER, exc),
            file=_sys.stderr,
        )
        _sys.exit(2)
    if len(_raw) > _SHIM_MAX_STDIN_BYTES:
        print(
            "matcher-shim [{}]: stdin exceeds {} bytes; refusing".format(
                _MATCHER, _SHIM_MAX_STDIN_BYTES
            ),
            file=_sys.stderr,
        )
        _sys.exit(2)
    try:
        payload = _json.loads(_raw or b"{}")
    except _json.JSONDecodeError as exc:
        print(
            "matcher-shim [{}]: malformed JSON on stdin: {}".format(_MATCHER, exc),
            file=_sys.stderr,
        )
        _sys.exit(2)
    try:
        fire = _shim_should_fire(payload)
    except Exception as exc:
        print(
            "matcher-shim [{}]: dispatch error: {}".format(_MATCHER, exc),
            file=_sys.stderr,
        )
        _sys.exit(2)
    if _os.environ.get("COPILOT_HOOK_DEBUG"):
        kind, _ = _shim_classify(_MATCHER)
        _sys.stderr.write(
            "matcher-shim [{}]: kind={} fired={}\n".format(_MATCHER, kind, fire)
        )
    if not fire:
        _sys.exit(0)
    # Replay a canonical payload into a fresh stdin so wrapped hooks enforce
    # the same schema even when the host sent the camelCase variant.
    _replay = _shim_replay_bytes(payload, _raw)
    _sys.stdin = _io.TextIOWrapper(_io.BytesIO(_replay), encoding="utf-8")
    rc = _original_main(_replay)
    if rc is None:
        rc = 0
    _sys.exit(int(rc))


# END MATCHER SHIM

def _original_main(stdin_bytes):
    # original script body begins below
    #!/usr/bin/env python3
    """Block git commit when staged files match security-sensitive patterns without review.

    Claude Code PreToolUse hook that enforces the "Do Router" gate per ADR-033
    Phase 4. Complements invoke_security_gate.py (Edit/Write) by also checking
    at commit time whether staged files touch auth/security paths.

    Hook Type: PreToolUse
    Matcher: Bash(git commit*)
    Exit Codes (Claude Hook Semantics, exempt from ADR-035):
        0 = allow: no security-sensitive files staged, or review evidence present.
        2 = block: security-sensitive files staged without review, or an
            infrastructure error reading the index. Paired with a top-level
            {"decision": "block"} payload, the recognized Claude Code PreToolUse
            contract (see invoke_branch_protection_guard.py). A previous version
            emitted {"decision": "deny"} with exit 0, which the harness ignored, so
            the gate never actually blocked (Issue #2521).
    """


    import json
    import os
    import re
    import subprocess
    import sys
    from datetime import UTC, datetime
    from pathlib import Path

    # Bootstrap: find lib directory via env var or manifest walk-up.
    # CLAUDE_PLUGIN_ROOT honored when set; otherwise walk up from __file__
    # looking for .claude-plugin/plugin.json (the plugin marker). Sibling
    # lib/ is the plugin's lib dir. Layout-independent: works in source
    # tree (.claude/) and in the deeper src/<provider>/hooks/<event>/ copy.
    _plugin_root = os.environ.get("CLAUDE_PLUGIN_ROOT")
    _lib_dir: str | None = None
    if _plugin_root:
        _lib_dir = str(Path(_plugin_root).resolve() / "lib")
    else:
        _cur = Path(__file__).resolve().parent
        while True:
            if (_cur / ".claude-plugin" / "plugin.json").is_file():
                _lib_dir = str(_cur / "lib")
                break
            if _cur.parent == _cur:
                break
            _cur = _cur.parent
    if _lib_dir is None or not os.path.isdir(_lib_dir):
        print(
            f"Plugin lib directory not found: {_lib_dir} "
            f"(CLAUDE_PLUGIN_ROOT={_plugin_root!r})",
            file=sys.stderr,
        )
        sys.exit(2)
    if _lib_dir not in sys.path:
        sys.path.insert(0, _lib_dir)

    from hook_utilities import get_project_directory, is_git_commit_command  # noqa: E402
    from hook_utilities.guards import skip_if_consumer_repo  # noqa: E402

    # Security-sensitive file path patterns
    _SECURITY_PATH_PATTERNS = [
        re.compile(r"(^|[/\\])[Aa]uth[/\\]"),
        re.compile(r"(^|[/\\])[Ss]ecurity[/\\]"),
        re.compile(r"\.env($|\.)"),
        re.compile(r"(^|[/\\])\.githooks[/\\]"),
        re.compile(r"(^|[/\\])secrets[/\\]"),
        re.compile(r"(?i)password"),
        re.compile(r"(^|[/\\])token"),
        re.compile(r"(^|[/\\])[Oo]auth[/\\]"),
        re.compile(r"(^|[/\\])[Jj]wt[/\\]"),
    ]

    # Session log patterns indicating security review
    _SECURITY_REVIEW_PATTERNS = [
        re.compile(r"security.*review", re.IGNORECASE),
        re.compile(r"security.*agent", re.IGNORECASE),
        re.compile(r"threat.*model", re.IGNORECASE),
        re.compile(r"OWASP", re.IGNORECASE),
        re.compile(r"/security-scan"),
        re.compile(r"subagent_type.*security", re.IGNORECASE),
    ]


    def get_staged_files() -> list[str]:
        """Get list of staged file paths.

        Raises:
            OSError: If git is not found or cannot be executed.
            subprocess.TimeoutExpired: If the command times out.
            subprocess.CalledProcessError: If git returns a non-zero exit code.
        """
        result = subprocess.run(
            ["git", "diff", "--cached", "--name-only"],
            capture_output=True,
            encoding="utf-8",
            errors="replace",
            timeout=10,
            check=True,
        )
        if result.stdout.strip():
            return result.stdout.strip().splitlines()
        return []


    def match_security_paths(files: list[str]) -> list[str]:
        """Return files matching security-sensitive patterns."""
        matched = []
        for f in files:
            for pattern in _SECURITY_PATH_PATTERNS:
                if pattern.search(f):
                    matched.append(f)
                    break
        return matched


    def find_security_evidence(project_dir: str) -> bool:
        """Check for security review evidence in the current session."""
        today = datetime.now(tz=UTC).strftime("%Y-%m-%d")

        # Check 1: Security report exists for today
        security_dir = Path(project_dir) / ".agents" / "security"
        if security_dir.is_dir():
            try:
                reports = list(security_dir.glob(f"*{today}*"))
                if reports:
                    return True
            except OSError:
                pass

        # Check 2: Session log contains security review evidence
        sessions_dir = Path(project_dir) / ".agents" / "sessions"
        if sessions_dir.is_dir():
            try:
                session_logs = sorted(
                    sessions_dir.glob(f"{today}-session-*.json"),
                    key=lambda p: p.stat().st_mtime,
                    reverse=True,
                )
            except OSError as exc:
                print(
                    f"Security commit gate could not enumerate session logs: {exc}",
                    file=sys.stderr,
                )
                session_logs = []

            for log_path in session_logs:
                try:
                    with log_path.open(encoding="utf-8", errors="replace") as handle:
                        for line in handle:
                            for pattern in _SECURITY_REVIEW_PATTERNS:
                                if pattern.search(line):
                                    return True
                except OSError as exc:
                    print(
                        f"Security commit gate could not read session log {log_path}: {exc}",
                        file=sys.stderr,
                    )
                    continue

        return False


    def write_block_response(reason: str) -> None:
        """Emit a PreToolUse block decision (matches invoke_branch_protection_guard.py).

        Claude Code recognizes a top-level ``{"decision": "block"}`` payload, paired
        with exit code 2, to deny a tool call. The previous ``{"decision": "deny"}``
        with exit 0 was not a recognized top-level value, so the gate's output was
        ignored and the security-sensitive commit proceeded (Issue #2521). The value
        ``deny`` is only valid under ``hookSpecificOutput.permissionDecision``.
        """
        print(json.dumps({"decision": "block", "reason": reason}, separators=(",", ":")))


    def main() -> int:
        """Main hook entry point."""
        if skip_if_consumer_repo("security-commit-gate"):
            return 0

        # Bypass: environment variable
        if os.environ.get("SKIP_SECURITY_GATE") == "true":
            return 0

        try:
            if sys.stdin.isatty():
                return 0

            input_json = sys.stdin.read()
            if not input_json.strip():
                return 0

            input_data = json.loads(input_json)
            tool_input = input_data.get("tool_input")
            if not isinstance(tool_input, dict):
                return 0

            command = tool_input.get("command", "")
            if not is_git_commit_command(command):
                return 0

            staged = get_staged_files()
            if not staged:
                return 0

            security_files = match_security_paths(staged)
            if not security_files:
                return 0

            project_dir = get_project_directory()
            if find_security_evidence(project_dir):
                return 0

            # Security files staged without review evidence: block the commit.
            file_list = "\n".join(f"  - {f}" for f in security_files)
            write_block_response(
                "SECURITY COMMIT GATE: Security review required before committing "
                "security-sensitive files.\n\n"
                f"Matched files:\n{file_list}\n\n"
                "Invoke the security agent:\n"
                "  Task(subagent_type='security', prompt='Review security-sensitive "
                "changes')\n\n"
                "Or create a security report in .agents/security/\n\n"
                "Bypass: Set SKIP_SECURITY_GATE=true (requires justification)"
            )
            return 2

        except (subprocess.CalledProcessError, subprocess.TimeoutExpired) as exc:
            # Infrastructure error enumerating staged files (not a git repo, index
            # lock, git timeout). Fail closed with a diagnostic so the failure is
            # distinguishable from a genuine security signal (Issue #2521).
            detail = ""
            stderr = getattr(exc, "stderr", None)
            if stderr:
                detail = (
                    stderr.decode("utf-8", errors="replace").strip()
                    if isinstance(stderr, bytes)
                    else str(stderr).strip()
                )
            print(
                f"Security commit gate could not read staged files: "
                f"{type(exc).__name__}. {detail}".strip(),
                file=sys.stderr,
            )
            write_block_response(
                "SECURITY COMMIT GATE: could not enumerate staged files "
                f"({type(exc).__name__}). Commit blocked as a precaution. "
                "Verify the repository state: git status."
            )
            return 2

        except Exception as exc:
            # Fail-closed on any other infrastructure error.
            print(f"Security commit gate error: {type(exc).__name__} - {exc}", file=sys.stderr)
            write_block_response(
                f"SECURITY COMMIT GATE FAILED due to an internal error: "
                f"{type(exc).__name__}. Commit blocked as a security precaution."
            )
            return 2
    return main()

_shim_dispatch()
